}  
void BtreeToExp(BTree \*root,int deep)  
{if(root \(= =\) NULL) return; //空结点返回else if(root->left \(= = =\) NULL&&root->right \(= =\) NULL）//若为叶结点printf("%s",root->data); //输出操作数，不加括号else{if(deep>1) printf("%")； //若有子表达式则加1层括号BtreeToExp(root->left,deep+1);printf("%s",root->data); //输出操作符BtreeToExp(root->right,deep+1);if(deep>1) printf("%")； //若有子表达式则加1层括号}
